import { useState, useEffect } from 'react';
import api from '../../services/api';
import toast from 'react-hot-toast';

export default function CompraForm() {
  const [proveedores, setProveedores] = useState([]);
  const [productos, setProductos] = useState([]);
  const [selectedProveedor, setSelectedProveedor] = useState('');
  const [items, setItems] = useState([]);
  const [currentProducto, setCurrentProducto] = useState('');
  const [cantidad, setCantidad] = useState(1);
  const [precioUnitario, setPrecioUnitario] = useState('');

  useEffect(() => {
    const fetchData = async () => {
      try {
        const [provRes, prodRes] = await Promise.all([
          api.get('/proveedores'), // Nota: Debes crear endpoint para proveedores, o usar datos fijos.
          api.get('/productos')
        ]);
        setProveedores(provRes.data);
        setProductos(prodRes.data);
      } catch (error) {
        toast.error('Error al cargar datos');
      }
    };
    fetchData();
  }, []);

  const addItem = () => {
    if (!currentProducto || cantidad <= 0 || !precioUnitario) return;
    const producto = productos.find(p => p.id === parseInt(currentProducto));
    if (!producto) return;
    setItems([...items, {
      producto_id: producto.id,
      producto_nombre: producto.nombre,
      cantidad: parseInt(cantidad),
      precio_unitario: parseFloat(precioUnitario)
    }]);
    setCurrentProducto('');
    setCantidad(1);
    setPrecioUnitario('');
  };

  const removeItem = (index) => {
    setItems(items.filter((_, i) => i !== index));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!selectedProveedor || items.length === 0) {
      toast.error('Complete proveedor y al menos un producto');
      return;
    }
    try {
      await api.post('/compras', {
        proveedor_id: selectedProveedor,
        items: items.map(i => ({
          producto_id: i.producto_id,
          cantidad: i.cantidad,
          precio_unitario: i.precio_unitario
        }))
      });
      toast.success('Compra registrada exitosamente');
      // reset form
      setSelectedProveedor('');
      setItems([]);
    } catch (error) {
      toast.error('Error al registrar compra');
    }
  };

  return (
    <div>
      <h1 className="text-2xl font-bold mb-4">Registrar Compra a Proveedor</h1>
      <form onSubmit={handleSubmit} className="bg-white p-4 rounded shadow">
        <div className="mb-4">
          <label className="block text-sm font-medium">Proveedor</label>
          <select value={selectedProveedor} onChange={e => setSelectedProveedor(e.target.value)} required className="w-full border p-2 rounded">
            <option value="">Seleccione proveedor</option>
            {proveedores.map(p => <option key={p.id} value={p.id}>{p.nombre}</option>)}
          </select>
        </div>
        <div className="border-t pt-4 mt-2">
          <h3 className="font-semibold mb-2">Agregar Producto</h3>
          <div className="grid grid-cols-3 gap-2">
            <select value={currentProducto} onChange={e => setCurrentProducto(e.target.value)} className="border p-2 rounded">
              <option value="">Seleccione producto</option>
              {productos.map(p => <option key={p.id} value={p.id}>{p.nombre}</option>)}
            </select>
            <input type="number" placeholder="Cantidad" value={cantidad} onChange={e => setCantidad(e.target.value)} className="border p-2 rounded" />
            <input type="number" step="0.01" placeholder="Precio unitario" value={precioUnitario} onChange={e => setPrecioUnitario(e.target.value)} className="border p-2 rounded" />
            <button type="button" onClick={addItem} className="bg-blue-500 text-white px-3 py-1 rounded">Agregar</button>
          </div>
        </div>
        {items.length > 0 && (
          <div className="mt-4">
            <h3 className="font-semibold">Productos agregados</h3>
            <ul className="list-disc pl-5">
              {items.map((item, idx) => (
                <li key={idx}>
                  {item.producto_nombre} - {item.cantidad} x ${item.precio_unitario} = ${item.cantidad * item.precio_unitario}
                  <button type="button" onClick={() => removeItem(idx)} className="text-red-600 ml-2">Eliminar</button>
                </li>
              ))}
            </ul>
          </div>
        )}
        <button type="submit" className="mt-4 bg-green-600 text-white px-4 py-2 rounded">Registrar Compra</button>
      </form>
    </div>
  );
}
